class AuthManager {
  final LocalStorageManager _storage;

  AuthManager(this._storage);

  Future<void> login(String token, String refreshToken,
      {DateTime? expiry, Map<String, dynamic>? profile}) async {
    await _storage.saveAuthToken(token);
    await _storage.saveRefreshToken(refreshToken);

    if (expiry != null) {
      await _storage.saveTokenExpiry(expiry);
    }

    if (profile != null) {
      await _storage.saveUserProfile(profile);
    }
  }

  Future<void> logout() async {
    await _storage.clearUserData();
  }

  bool isAuthenticated() {
    final token = _storage.getAuthToken();
    if (token == null || token.isEmpty) return false;
    return !_storage.isTokenExpired();
  }

  String? getCurrentToken() {
    if (isAuthenticated()) {
      return _storage.getAuthToken();
    }
    return null;
  }

  UserProfile? getCurrentUser() {
    final profileData = _storage.getUserProfile();
    if (profileData != null) {
      return UserProfile.fromJson(profileData);
    }
    return null;
  }
}